// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function render(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const safeForecast = Array.isArray(props.forecast) ? props.forecast : [];
  const forecastStrip = safeForecast.slice(0, 5);
  const normalizedCondition = (props.condition || '').trim().toLowerCase();
  const currentConditionIcon = (() => {
    if (normalizedCondition.includes('sun') || normalizedCondition === 'clear') return 'sun';
    if (normalizedCondition.includes('partly') && normalizedCondition.includes('cloud')) return 'cloud-sun';
    if (normalizedCondition.includes('cloud') || normalizedCondition.includes('overcast')) return 'cloud';
    if (normalizedCondition.includes('rain') || normalizedCondition.includes('drizzle') || normalizedCondition.includes('shower')) return 'cloud-rain';
    if (normalizedCondition.includes('storm') || normalizedCondition.includes('thunder')) return 'cloud-lightning';
    if (normalizedCondition.includes('snow') || normalizedCondition.includes('sleet') || normalizedCondition.includes('blizzard')) return 'cloud-snow';
    if (normalizedCondition.includes('mist') || normalizedCondition.includes('fog') || normalizedCondition.includes('haze')) return 'cloud-fog';
    if (normalizedCondition.includes('wind')) return 'wind';
    return 'cloud';
  })();

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        shadow="md"
        radius="xl"
      >
        <Stack gap="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-2)">
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Current Weather
            </Text>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {props.city}
            </Heading>
          </Stack>

          <Row align="center" justify="between" gap="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-1)">
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-700, #0369a1)">
                {props.temperature}°{props.unit}
              </Text>
              <Row align="center" gap="var(--ggui-spacing-2)">
                {currentConditionIcon ? <Icon name={currentConditionIcon} size={24} color="var(--ggui-color-primary-600, #0284c7)" /> : null}
                <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
                  {props.condition}
                </Text>
              </Row>
            </Stack>

            <Box
              padding="var(--ggui-spacing-4)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
            >
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Details
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity: {props.humidity}%
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind: {props.windSpeed} km/h
                </Text>
              </Stack>
            </Box>
          </Row>

          <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin="var(--ggui-spacing-2)" />

          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              5-Day Forecast
            </Text>
            <Box padding="0" margin="0" style={{ overflowX: 'auto' }}>
              <Row gap="var(--ggui-spacing-2)">
                {Array.from({ length: 5 }).map((_, index) => {
                  const dayForecast = forecastStrip[index];
                  return (
                    <Box key={`forecast-slot-${index}`}>
                      <Stack align="center" gap="var(--ggui-spacing-1)">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {dayForecast?.day ?? '—'}
                        </Text>
                        <Icon
                          name={dayForecast?.icon ?? 'cloud'}
                          size={20}
                          color="var(--ggui-color-primary-600, #0284c7)"
                        />
                        <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                          {dayForecast?.high !== undefined ? `${dayForecast.high}°` : '—'} / {dayForecast?.low !== undefined ? `${dayForecast.low}°` : '—'}
                        </Text>
                      </Stack>
                    </Box>
                  );
                })}
              </Row>
            </Box>
          </Stack>
        </Stack>
      </Card>
    </Container>

  );
}

