import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Render(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const totalSteps = 5;
  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [submitted, setSubmitted] = useState<boolean>(false);

  const isEmailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = name.trim().length === 0 ? 'Name is required.' : '';
  const emailError = email.trim().length === 0 ? 'Email is required.' : !isEmailValid ? 'Please enter a valid email address.' : '';

  const stepValid = useMemo(() => {
    if (step === 1) return name.trim().length > 0 && isEmailValid;
    if (step === 2) return satisfaction >= 1 && satisfaction <= 5;
    if (step === 3) return true;
    if (step === 4) return comments.length <= 500;
    return true;
  }, [step, name, isEmailValid, satisfaction, comments.length]);

  const satisfactionOptions = useMemo(
    () =>
      [1, 2, 3, 4, 5].map((value, index) => ({
        value: String(value),
        label: (props.satisfactionLabels || [])[index] ?? '',
      })),
    [props.satisfactionLabels],
  );

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        return prev.includes(feature) ? prev : [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const goNext = useCallback(() => {
    if (!stepValid) return;
    setStep((prev) => Math.min(totalSteps, prev + 1));
  }, [stepValid]);

  const goBack = useCallback(() => {
    setStep((prev) => Math.max(1, prev - 1));
  }, []);

  const onSubmitSurvey = useCallback(() => {
    if (submitted || !(name.trim().length > 0 && isEmailValid && satisfaction >= 1 && satisfaction <= 5)) return;
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features,
      comments: comments.trim(),
    };
    submit(payload);
    (props as Props & { onSubmit?: (payload: ActionSubmitPayload) => void }).onSubmit?.(payload);
    setSubmitted(true);
  }, [name, email, satisfaction, features, comments, submitted, props, isEmailValid, submit]);
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" border radius="lg" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Row align="center" justify="between">
              <Heading level={3} color="var(--ggui-color-onSurface)">
                Survey Form
              </Heading>
              <Badge variant="primary">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={step} max={totalSteps} size="md" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" border radius="lg" shadow="sm">
          <Stack gap="var(--ggui-spacing-6)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Basic Information</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  error={nameError}
                  placeholder="Enter your name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  error={emailError}
                  helperText="We'll only use this for survey follow-up."
                  placeholder="you@example.com"
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Satisfaction</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction ? String(satisfaction) : ''}
                  onChange={(value) => setSatisfaction(Number(value))}
                  options={satisfactionOptions}
                  direction="vertical"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Feature Interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">Select all that apply.</Text>
                {(props.featureOptions || []).length === 0 ? (
                  <Alert variant="info">No features available.</Alert>
                ) : (
                  <Stack gap="var(--ggui-spacing-2)">
                    {(props.featureOptions || []).map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={features.includes(feature)}
                        onChange={(checked) => toggleFeature(feature, checked)}
                      />
                    ))}
                  </Stack>
                )}
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Comments</Heading>
                <TextArea
                  label="Additional comments"
                  value={comments}
                  onChange={setComments}
                  rows={6}
                  maxLength={500}
                  showCount
                  helperText="Optional. Share any additional thoughts."
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {comments.length}/500 characters
                </Text>
              </Stack>
            )}

            {step === 5 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review Your Answers</Heading>
                <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {name || '-'}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {email || '-'}</Text>
                    <Text><Text is="span" weight="semibold">Satisfaction:</Text> {satisfaction || '-'}</Text>
                    <Text>
                      <Text is="span" weight="semibold">Features:</Text>{' '}
                      {features.length > 0 ? features.join(', ') : 'None selected'}
                    </Text>
                    <Text><Text is="span" weight="semibold">Comments:</Text> {comments || 'No comments'}</Text>
                  </Stack>
                </Card>
                {submitted && <Alert variant="success">Survey submitted successfully.</Alert>}
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />

            <Row justify="between" align="center">
              <Button variant="outline" onClick={goBack} disabled={step === 1}>
                Back
              </Button>
              {step < totalSteps ? (
                <Button variant="primary" onClick={goNext} disabled={!stepValid}>
                  Next
                </Button>
              ) : (
                 <Button variant="primary" onClick={onSubmitSurvey} disabled={submitted}>
                  Submit
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = {
  action: 'create' | 'move' | 'edit' | 'delete';
  taskId: string;
  data: {
    column: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    dueDate?: string;
  };
};


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




function RenderKanban(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const normalizedColumns = useMemo(() => {
    const provided = (props.columns ?? []).filter((c) => c?.id) as Array<{ id?: string; name?: string }>;
    const required = [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' },
    ];
    const merged = [...provided];
    required.forEach((req) => {
      if (!merged.some((c) => c.id === req.id)) {
        merged.push(req);
      }
    });
    return merged;
  }, [props.columns]);

  const [tasks, setTasks] = useState<Props['tasks']>(props.tasks ?? []);
  const [addingColumn, setAddingColumn] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');

  useEffect(() => {
    setTasks(props.tasks ?? []);
  }, [props.tasks]);

  useEffect(() => {
    const latest = taskChanged.latest;
    if (!latest?.task?.id) return;
    setTasks((prev) => {
      const taskId = latest.task?.id as string;
      if (latest.action === 'delete') {
        return prev.filter((t) => t?.id !== taskId);
      }

      const existingIndex = prev.findIndex((t) => t?.id === taskId);
      if (existingIndex === -1) {
        return [...prev, latest.task];
      }
      const next = [...prev];
      next[existingIndex] = { ...next[existingIndex], ...latest.task };
      return next;
    });
  }, [taskChanged.latest]);

  const priorityOptions = useMemo(
    () => [
      { value: 'low', label: 'Low' },
      { value: 'medium', label: 'Medium' },
      { value: 'high', label: 'High' },
    ],
    []
  );

  const moveOptionsByColumn = useMemo(() => {
    return normalizedColumns.map((c) => ({ value: c.id ?? '', label: c.name ?? c.id ?? 'Column' }));
  }, [normalizedColumns]);

  const totalTasks = tasks.length;
  const doneColumnId = normalizedColumns.find((c) => (c.name ?? '').toLowerCase() === 'done')?.id ?? 'done';
  const completedCount = tasks.filter((t) => (t.column ?? '') === doneColumnId).length;

  const todoColumnId = useMemo(() => {
    const byId = normalizedColumns.find((c) => (c.id ?? '').toLowerCase() === 'todo')?.id;
    if (byId) return byId;
    const byName = normalizedColumns.find((c) => (c.name ?? '').toLowerCase().includes('to do'))?.id;
    return byName ?? normalizedColumns[0]?.id ?? 'todo';
  }, [normalizedColumns]);

  const groupedTasks = useMemo(() => {
    const validColumnIds = new Set(normalizedColumns.map((c) => c.id ?? ''));
    const fallbackColumnId = normalizedColumns[0]?.id ?? 'todo';
    return tasks.reduce<Record<string, Props['tasks']>>((acc, task) => {
      const rawColumn = task?.column ?? fallbackColumnId;
      const normalizedColumn = validColumnIds.has(rawColumn) ? rawColumn : fallbackColumnId;
      if (!acc[normalizedColumn]) acc[normalizedColumn] = [];
      acc[normalizedColumn].push({ ...task, column: normalizedColumn });
      return acc;
    }, normalizedColumns.reduce<Record<string, Props['tasks']>>((acc, column) => {
      const colId = column.id ?? '';
      acc[colId] = [];
      return acc;
    }, {}));
  }, [normalizedColumns, tasks]);

  const getPriorityVariant = (priority?: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  };

  const handleMoveTask = useCallback(
    (taskId: string, column: string) => {
      setTasks((prev) => prev.map((t) => (t?.id === taskId ? { ...t, column } : t)));
      taskUpdate({ action: 'move', taskId, data: { column } });
    },
    [taskUpdate]
  );

  const startEdit = useCallback((taskId: string, currentTitle?: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle ?? '');
  }, []);

  const saveEdit = useCallback(
    (taskId: string) => {
      const nextTitle = editingTitle.trim();
      if (!nextTitle) return;
      const current = tasks.find((t) => t?.id === taskId);
      setTasks((prev) => prev.map((t) => (t?.id === taskId ? { ...t, title: nextTitle } : t)));
      taskUpdate({
        action: 'edit',
        taskId,
        data: {
          column: current?.column ?? todoColumnId,
          title: nextTitle,
          priority: current?.priority ?? 'medium',
          assignee: current?.assignee ?? '',
          dueDate: current?.dueDate ?? '',
        },
      });
      setEditingTaskId(null);
      setEditingTitle('');
    },
    [editingTitle, taskUpdate, tasks, todoColumnId]
  );
  const handleAddTask = useCallback(
    () => {
      const title = newTitle.trim();
      if (!title) return;
      const newId = `task-${Date.now()}`;
      const task = { id: newId, title, priority: newPriority, assignee: '', column: todoColumnId, dueDate: '' };
      setTasks((prev) => [...prev, task]);
      taskUpdate({ action: 'create', taskId: newId, data: { column: todoColumnId, title, priority: newPriority, assignee: '', dueDate: '' } });
      setAddingColumn(null);
      setNewTitle('');
      setNewPriority('medium');
    },
    [newPriority, newTitle, taskUpdate, todoColumnId]
  );

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-4)"
          radius="lg"
          shadow="sm"
          border
        >
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Team Task Board</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {completedCount} of {totalTasks} completed
              </Text>
            </Stack>
            <Badge variant="primary" size="lg">
              Total: {totalTasks}
            </Badge>
          </Row>
          {taskChanged.latest && (
            <Box
              margin="var(--ggui-spacing-2) 0 0 0"
              padding="var(--ggui-spacing-2)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
            >
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Live updates: {taskChanged.all.length} event(s) received
              </Text>
            </Box>
          )}
        </Card>

        <Row gap="var(--ggui-spacing-4)">
