                                ) : (
                                  <Button size="sm" variant="outline" onClick={() => startEdit(taskId, task.title)}>
                                    Edit
                                  </Button>
                                )}
                              </Row>
                            </Stack>
                          </Card>
                        );
                      })
                    )}
                  </Stack>

                  {addingColumn === colId ? (
                    <Card padding="var(--ggui-spacing-3)" border radius="md" shadow="none">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input label="Task title" value={newTitle} onChange={setNewTitle} placeholder="New task title" />
