const categoryColor = (category?: string) => {
  const key = (category || 'unknown').toLowerCase().replace(/-/g, ' ');
  const map: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-error-100, #fee2e2)',
    'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
    'transition metal': 'var(--ggui-color-primary-100, #e0f2fe)',
    'post-transition metal': 'var(--ggui-color-info-100, #cffafe)',
    metalloid: 'var(--ggui-color-success-100, #dcfce7)',
    nonmetal: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    halogen: 'var(--ggui-color-warning-200, #fde68a)',
    'noble gas': 'var(--ggui-color-primary-200, #bae6fd)',
    lanthanide: 'var(--ggui-color-success-200, #bbf7d0)',
    actinide: 'var(--ggui-color-error-200, #fecaca)',
    unknown: 'var(--ggui-color-outlineVariant, #e4e4e7)',
  };
  return map[key] || 'var(--ggui-color-outlineVariant, #e4e4e7)';
};

export default function Render(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Props['elements'][number] | null>(null);

  const safeElements = useMemo(() => props.elements ?? [], [props.elements]);

  const filteredElements = useMemo(() => {
    const term = search.trim().toLowerCase();
    if (!term) return safeElements;
    return safeElements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(term) || symbol.includes(term);
    });
  }, [safeElements, search]);

  useEffect(() => {
    if (!selected && filteredElements.length > 0) {
      setSelected(filteredElements[0]);
    }
    if (selected) {
      const exists = filteredElements.some(
        (el) => el.atomicNumber === selected.atomicNumber && el.symbol === selected.symbol,
      );
      if (!exists) setSelected(null);
    }
  }, [filteredElements, selected]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    safeElements.forEach((el) => unique.add(el.category || 'unknown'));
    return Array.from(unique);
  }, [safeElements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
