          >
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
                gap: 'var(--ggui-spacing-2)',
              }}
            >
              {filteredElements.map((el, index) => {
                const isSelected =
                  selected?.atomicNumber === el.atomicNumber && selected?.symbol === el.symbol;
                return (
                  <Card
                    key={`${el.atomicNumber || 'n'}-${el.symbol || 's'}-${index}`}
                    as={Clickable}
                    onClick={() => setSelected(el)}
                    padding="var(--ggui-spacing-2)"
                    shadow={isSelected ? 'md' : 'sm'}
                    border
                    radius="md"
                    hoverStyle={{ opacity: 0.9 }}
                    style={{
                      gridColumn: el.col ?? 1,
                      gridRow: el.row ?? 1,
                      minHeight: '72px',
                      background: categoryColor(el.category),
                      borderColor: isSelected
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                      position: 'relative',
                    }}
                  >
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      style={{ position: 'absolute', top: '6px', left: '8px' }}
                    >
                      {el.atomicNumber ?? '—'}
                    </Text>
                    <Stack align="center" justify="center" style={{ height: '100%' }}>
                      <Text size="xl" weight="bold" align="center">
                        {el.symbol ?? '—'}
                      </Text>
                    </Stack>
                  </Card>
                );
              })}
            </Box>
          </Box>
        )}

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4}>Selected Element Details</Heading>
            {selected ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><strong>Name:</strong> {selected.name ?? '—'}</Text>
                <Text><strong>Symbol:</strong> {selected.symbol ?? '—'}</Text>
                <Text><strong>Atomic Number:</strong> {selected.atomicNumber ?? '—'}</Text>
                <Text><strong>Atomic Weight:</strong> {selected.atomicWeight ?? '—'}</Text>
                <Text><strong>Category:</strong> {selected.category ?? '—'}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
