import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Render(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const product = props.product ?? {};
  const stock = typeof product.stock === 'number' && product.stock > 0 ? product.stock : 0;
  const [quantity, setQuantity] = useState<number>(1);
  const [activeTab, setActiveTab] = useState<string>('description');

  const rating = useMemo(() => {
    const raw = typeof product.rating === 'number' ? product.rating : 0;
    return Math.max(0, Math.min(5, raw));
  }, [product.rating]);

  const formattedPrice = useMemo(() => {
    const price = typeof product.price === 'number' ? product.price : 0;
    const currencyCode = typeof product.currency === 'string' ? product.currency : 'USD';
    const currencySymbolMap: Record<string, string> = {
      USD: '$',
      EUR: '€',
      GBP: '£',
      JPY: '¥',
      INR: '₹',
      CAD: 'C$',
      AUD: 'A$'
    };

    try {
      return new Intl.NumberFormat(undefined, {
        style: 'currency',
        currency: currencyCode,
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
      }).format(price);
    } catch {
      const symbol = currencySymbolMap[currencyCode.toUpperCase()] ?? `${currencyCode.toUpperCase()} `;
      return `${symbol}${new Intl.NumberFormat(undefined, {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
      }).format(price)}`;
    }
  }, [product.currency, product.price]);
  const specifications = Array.isArray(product.specifications) ? product.specifications : [];
  const reviews = Array.isArray(product.reviews) ? product.reviews : [];
  const displayReviewCount = typeof product.reviewCount === 'number' && product.reviewCount >= 0 ? product.reviewCount : reviews.length;
  useEffect(() => {
    if (quantity > stock && stock > 0) {
      setQuantity(stock);
    }
    if (stock === 0) {
      setQuantity(1);
    }
  }, [quantity, stock]);

  const decreaseQuantity = useCallback(() => {
    setQuantity((prev) => Math.max(1, prev - 1));
  }, []);

  const increaseQuantity = useCallback(() => {
    setQuantity((prev) => Math.min(Math.max(1, stock), prev + 1));
  }, [stock]);

  const handleAddToCart = useCallback(() => {
    if (!product.id || stock <= 0) return;
    const boundedQuantity = Math.min(Math.max(1, quantity), stock);
    addToCart({ productId: product.id, quantity: boundedQuantity });
  }, [addToCart, product.id, quantity, stock]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" border>
          <Row
            gap="var(--ggui-spacing-6)"
            align="start"
            style={{ flexWrap: 'wrap' }}
          >
            <Image
              src=""
              alt={`Product image placeholder for ${product.name ?? 'Unnamed Product'}` }
              width="100%"
              height={260}
              objectFit="cover"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
              fallback={
                <Box
                  background="var(--ggui-color-primary-100, #e0f2fe)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  padding="var(--ggui-spacing-8)"
                  style={{ minHeight: '260px', display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column' }}
                >
                  <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Product Image Placeholder</Text>
                  <Text
                    variant="bodyLarge"
                    weight="semibold"
                    color="var(--ggui-color-primary-700, #0369a1)"
                    align="center"
                  >
                    {product.name ?? 'Unnamed Product'}
                  </Text>
                </Box>
              }
            />

            <Stack gap="var(--ggui-spacing-4)" style={{ flex: '1 1 320px' }}>
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">{product.name ?? 'Unnamed Product'}</Heading>
              <Text size="xl" weight="bold" color="var(--ggui-color-primary-700, #0369a1)">
                {formattedPrice}
              </Text>

              <Row gap="var(--ggui-spacing-2)" align="center">
                <Row gap="var(--ggui-spacing-1)">
                  {[1, 2, 3, 4, 5].map((star) => {
                    const iconName = rating >= star ? 'star' : rating >= star - 0.5 ? 'star-half' : 'star-off';
                    return (
                      <Icon
                        key={star}
                        name={iconName}
                        color={rating >= star - 0.5 ? 'var(--ggui-color-warning, #d97706)' : 'var(--ggui-color-outline, #d4d4d8)'}
                        size={18}
                      />
                    );
                  })}
                </Row>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {rating.toFixed(1)} ({displayReviewCount === 0 ? 'No reviews' : displayReviewCount === 1 ? '1 review' : `${displayReviewCount} reviews`})
                </Text>
              </Row>

              <Badge variant={stock <= 0 ? 'error' : stock > 5 ? 'success' : 'warning'} size="md">
                {stock <= 0 ? 'Out of Stock' : stock > 5 ? 'In Stock' : 'Low Stock'}
              </Badge>
            </Stack>
          </Row>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border>
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Text color="var(--ggui-color-onSurface, #18181b)">
                    {product.description ?? 'No description available.'}
                  </Text>
                )
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: specifications.length > 0 ? (
                  <Table
                    columns={[
                      { key: 'key', header: 'Specification' },
                      { key: 'value', header: 'Value' }
                    ]}
                    data={specifications.map((item, index) => {
                      const spec = item as { key?: string; value?: string; name?: string };
                      return {
                        id: `spec-${index}`,
                        key: spec.key ?? spec.name ?? `Spec ${index + 1}`,
                        value: spec.value ?? '-'
                      };
                    })}
                    striped
                    bordered
                  />
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">No specifications provided.</Text>
                )
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: reviews.length > 0 ? (
                  <Stack gap="var(--ggui-spacing-4)">
                    {reviews.map((review, index) => {
                      const r = review as { author?: string; rating?: number; text?: string; date?: string };
                      const reviewRating = Math.max(0, Math.min(5, Math.round(r.rating ?? 0)));
                      return (
                        <Card key={`review-${index}`} padding="var(--ggui-spacing-4)" border shadow="none">
                          <Stack gap="var(--ggui-spacing-2)">
                            <Row justify="between" align="center">
                              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{r.author ?? 'Anonymous'}</Text>
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{r.date ?? '-'}</Text>
                            </Row>
                            <Row gap="var(--ggui-spacing-1)">
                              {[1, 2, 3, 4, 5].map((s) => (
                                <Icon
                                  key={s}
                                  name="star"
                                  size={16}
                                  color={s <= reviewRating ? 'var(--ggui-color-warning, #d97706)' : 'var(--ggui-color-outline, #d4d4d8)'}
                                />
                              ))}
                            </Row>
                            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">{r.text ?? ''}</Text>
                          </Stack>
                        </Card>
                      );
                    })}
                  </Stack>
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">No reviews yet.</Text>
                )
              }
            ]}
          />
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border>
          <Row justify="between" align="center" gap="var(--ggui-spacing-4)" style={{ flexWrap: 'wrap' }}>
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Quantity</Text>
              <Button variant="outline" size="sm" onPress={decreaseQuantity} disabled={quantity <= 1}>
                -
              </Button>
              <Box
                paddingX="var(--ggui-spacing-4)"
                paddingY="var(--ggui-spacing-2)"
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
              >
                <Text weight="medium" color="var(--ggui-color-onSurface, #18181b)">{quantity}</Text>
              </Box>
              <Button variant="outline" size="sm" onPress={increaseQuantity} disabled={stock <= 0 || quantity >= stock}>
                +
              </Button>
            </Row>

            <Button
              variant="primary"
              size="md"
              onPress={handleAddToCart}
              disabled={stock <= 0 || !product.id}
            >
              Add to Cart
            </Button>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}

