import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




function RenderComponent(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [draft, setDraft] = useState('');
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setAllMessages(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  useEffect(() => {
    const latestTyping = typing.latest;
    if (!latestTyping || latestTyping.sender === props.currentUser) return;
    if (latestTyping.active) {
      setTypingUser(latestTyping.sender ?? 'Someone');
    } else {
      setTypingUser(null);
    }
  }, [typing.latest, props.currentUser]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [allMessages, typingUser]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    (allMessages ?? []).forEach((m) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === m.sender) {
        last.messages.push(m);
      } else {
        groups.push({ sender: m.sender, messages: [m] });
      }
    });
    return groups;
  }, [allMessages]);

  const formatTime = useCallback((timestamp?: string) => {
    if (!timestamp) return '';
    const d = new Date(timestamp);
    if (Number.isNaN(d.getTime())) return '';
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }, []);

  const handleSend = useCallback(() => {
    const text = draft.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage(payload);
    setAllMessages((prev) => [...prev, { sender: props.currentUser, text: payload.text, timestamp: payload.timestamp }]);
    setDraft('');
  }, [draft, sendMessage, props.currentUser]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card border radius="lg" padding="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Badge variant="primary">{props.participantCount} participants</Badge>
              {typingUser ? <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{typingUser} is typing…</Text> : null}
            </Row>
          </Row>

          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-lg)"
          >
            <Box
              as="div"
              ref={scrollRef}
              style={{ maxHeight: '60vh', overflowY: 'auto' }}
            >
              <Stack gap="var(--ggui-spacing-4)">
                {groupedMessages.length === 0 ? (
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">No messages yet.</Text>
                ) : (
                  groupedMessages.map((group, groupIndex) => {
                    const isCurrentUser = (group.sender ?? '') === props.currentUser;
                    return (
                      <Stack key={`${group.sender ?? 'unknown'}-${groupIndex}`} align={isCurrentUser ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{group.sender ?? 'Unknown'}</Text>
                        <Stack gap="var(--ggui-spacing-1)" align={isCurrentUser ? 'end' : 'start'}>
                          {group.messages.map((msg, idx) => (
                            <Box
                              key={`${groupIndex}-${idx}-${msg.timestamp ?? ''}`}
                              padding="var(--ggui-spacing-2)"
                              background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                              borderRadius="var(--ggui-shape-radius-md)"
                            >
                              <Stack gap="var(--ggui-spacing-1)">
                                <Text
                                  variant="bodySmall"
                                  color={isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                >
                                  {msg.text ?? ''}
                                </Text>
                                <Text
                                  variant="caption"
                                  color={isCurrentUser ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                  align={isCurrentUser ? 'right' : 'left'}
                                >
                                  {formatTime(msg.timestamp)}
                                </Text>
                              </Stack>
                            </Box>
                          ))}
                        </Stack>
                      </Stack>
                    );
                  })
                )}
              </Stack>
            </Box>
          </Box>

          <Divider color="var(--ggui-color-outlineVariant)" margin="var(--ggui-spacing-2)" />

          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box as="div" style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder="Type your message..."
                value={draft}
                onChange={setDraft}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button variant="primary" onClick={handleSend} disabled={!draft.trim()}>
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

export default function render(props: Props) {
  return <RenderComponent {...props} />;
}

