// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Render(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stockMap, setStockMap] = useState<Record<string, { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>({});
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [now, setNow] = useState<Date>(new Date());
  const [flashMap, setFlashMap] = useState<Record<string, boolean>>({});

  useEffect(() => {
    const initialMap: Record<string, { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }> = {};
    (props.stocks || []).forEach((stock) => {
      const key = stock.symbol || `stock-${stock.name || 'unknown'}`;
      initialMap[key] = stock;
    });
    setStockMap(initialMap);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest?.symbol) return;
    const symbol = priceUpdate.latest.symbol;
    setStockMap((prev) => ({
      ...prev,
      [symbol]: {
        ...prev[symbol],
        symbol,
        price: priceUpdate.latest?.price ?? prev[symbol]?.price,
        change: priceUpdate.latest?.change ?? prev[symbol]?.change,
        changePercent: priceUpdate.latest?.changePercent ?? prev[symbol]?.changePercent,
      },
    }));
    setLastUpdated(new Date());
    setFlashMap((prev) => ({ ...prev, [symbol]: true }));
    const timeout = setTimeout(() => {
      setFlashMap((prev) => ({ ...prev, [symbol]: false }));
    }, 700);
    return () => clearTimeout(timeout);
  }, [priceUpdate.latest]);

  useEffect(() => {
    if (!marketStatus.latest) return;
    const ts = marketStatus.latest.timestamp;
    setLastUpdated(ts ? new Date(ts) : new Date());
  }, [marketStatus.latest]);

  const stocks = useMemo(() => Object.values(stockMap), [stockMap]);

  const formatCurrency = useCallback((value?: number) => {
    if (typeof value !== 'number') return '--';
    return `$${value.toFixed(2)}`;
  }, []);

  const formatSigned = useCallback((value?: number) => {
    if (typeof value !== 'number') return '--';
    return `${value >= 0 ? '+' : ''}${value.toFixed(2)}`;
  }, []);

  const formatPercent = useCallback((value?: number) => {
    if (typeof value !== 'number') return '--';
    return `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`;
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          border
          shadow="sm"
          radius="lg"
        >
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={1} color="var(--ggui-color-onSurface)">
                Market Watch
              </Heading>
              <Badge
                variant={marketStatus.latest?.status === 'open' ? 'success' : 'default'}
                size="md"
              >
                {marketStatus.latest?.status || 'status unavailable'}
              </Badge>
            </Row>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {Math.max(0, Math.floor((now.getTime() - lastUpdated.getTime()) / 1000))}s ago
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Local Time: {now.toLocaleTimeString()}
            </Text>
          </Stack>
        </Card>

        {stocks.length === 0 ? (
          <Card padding="var(--ggui-spacing-6)" border>
            <Text color="var(--ggui-color-onSurfaceVariant)">
              No stock data available.
            </Text>
          </Card>
        ) : (
          <CardGrid columns={{ sm: 1, lg: 3 }} gap={16}>
            {stocks.map((stock, index) => {
              const symbol = stock.symbol || `stock-${index}`;
              const isPositive = (stock.change ?? 0) >= 0;
              const trendColor = isPositive
                ? 'var(--ggui-color-success)'
                : 'var(--ggui-color-error)';
              const arrow = isPositive ? '▲' : '▼';

              return (
                <Card
                  key={symbol}
                  padding="var(--ggui-spacing-6)"
                  border
                  shadow="sm"
                  radius="lg"
                >
                  <Box
                    padding="var(--ggui-spacing-2)"
                    borderRadius="var(--ggui-shape-radius-md)"
                    background={flashMap[symbol] ? 'var(--ggui-color-container)' : 'var(--ggui-color-surfaceVariant)'}
                    style={{
                      border: `1px solid ${trendColor}`,
                      animation: flashMap[symbol] ? 'ggui-fadeIn 300ms ease-out' : 'none',
                      transition: 'background-color 300ms ease-out, border-color 200ms ease-out',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface)">
                        {stock.symbol || '--'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name || 'Unknown Company'}
                      </Text>
                      <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />
                      <Text size="2xl" weight="semibold" color="var(--ggui-color-onSurface)">
                        {formatCurrency(stock.price)}
                      </Text>
                      <Row justify="between" align="center">
                        <Text variant="body" color={trendColor}>
                          {formatSigned(stock.change)}
                        </Text>
                        <Text variant="body" weight="semibold" color={trendColor}>
                          {arrow} {formatPercent(stock.changePercent)}
                        </Text>
                      </Row>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };



const DEFAULT_AVATARS = ['😀', '🚀', '🎨', '🧠'];

const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

export default function Render(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const avatars = props.avatarOptions && props.avatarOptions.length > 0 ? props.avatarOptions : DEFAULT_AVATARS;
  const roles = props.roleOptions && props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other'];

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(props.initialProfile?.avatar ?? avatars[0] ?? '😀');
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');

  const nameError = name.trim().length === 0 ? 'Name is required' : '';
  const emailError = email.trim().length === 0 ? 'Email is required' : !isValidEmail(email) ? 'Please enter a valid email address' : '';

  const canGoNext = useMemo(() => {
    if (step === 1) return !nameError && !emailError;
    if (step === 2) return true;
    return true;
  }, [step, nameError, emailError, role, theme]);

  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const goNext = useCallback(() => {
    if (step < 3 && canGoNext) setStep((s) => s + 1);
  }, [step, canGoNext]);

  const goBack = useCallback(() => {
    if (step > 1) setStep((s) => s - 1);
  }, [step]);

  const onComplete = useCallback(() => {
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role: role || 'Other',
      emailNotifications,
      theme,
    });
  }, [complete, name, email, avatar, role, emailNotifications, theme]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" border shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row align="center" justify="between">
              <Heading level={3} color="var(--ggui-color-onSurface)">
                Onboarding Wizard
              </Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          border
          shadow="sm"
          radius="lg"
        >
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4} color="var(--ggui-color-onSurface)">Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  error={nameError || undefined}
                  placeholder="Enter your full name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  error={emailError || undefined}
                  placeholder="you@example.com"
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Choose Avatar</Text>
                  <Row gap="var(--ggui-spacing-2)" wrap>
                    {avatars.map((emoji) => (
                      <Card
                        key={emoji}
                        as={Clickable}
                        onClick={() => setAvatar(emoji)}
                        padding="var(--ggui-spacing-2)"
                        border
                        radius="md"
                        shadow="none"
                        style={{
                          borderColor: avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === emoji ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                        }}
                      >
                        <Text size="2xl" is="span">{emoji}</Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4} color="var(--ggui-color-onSurface)">Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  required
                  options={roles.map((item) => ({ value: item, label: item }))}
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4} color="var(--ggui-color-onSurface)">Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" border shadow="none" radius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {name}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {email}</Text>
                    <Text><Text is="span" weight="semibold">Avatar:</Text> {avatar}</Text>
                    <Text><Text is="span" weight="semibold">Role:</Text> {role || 'Other'}</Text>
                    <Text><Text is="span" weight="semibold">Notifications:</Text> {emailNotifications ? 'On' : 'Off'}</Text>
                    <Text><Text is="span" weight="semibold">Theme:</Text> {theme}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4)" color="var(--ggui-color-outlineVariant)" />

          <Row justify="between" align="center">
            <Button variant="ghost" onClick={goBack} disabled={step === 1}>
              Back
            </Button>
            {step < 3 ? (
              <Button variant="primary" onClick={goNext} disabled={!canGoNext}>
                Next
              </Button>
            ) : (
              <Row gap="var(--ggui-spacing-2)">
                <Button variant="outline" onClick={goBack}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={onComplete}>
                  Complete Setup
                </Button>
              </Row>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
